rubric.en:
Expected code/algorithm:
vertexcover(V, E, k) {
  count = 0;
  foreach v from V {
    choose x[v] from { 0, 1 };
    count = count + x[v];
  }
  if (count > k) failure;
  foreach e from E {
    if ((x[e[0]] == 0) && (x[e[1]] == 0)) failure;
  }
  success;
}

